@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private int StartItem => TotalCount == 0 ? 0 : (Page - 1) * PageSize + 1;
    private int EndItem => Math.Min(Page * PageSize, TotalCount);

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@namespace sv_2c358796a35e4aa6b17cb47427fc2c1a.Components.Pages.Catalog

<nav class="catalog-pagination" aria-label="Product pagination">
    <button class="btn btn-page"
            disabled="@(CurrentPage <= 1)"
            @onclick="@(() => GoToPage(CurrentPage - 1))">
        Previous
    </button>

    @for (int i = 1; i <= TotalPages; i++)
    {
        var pageNum = i;
        <button class="btn btn-page @(pageNum == CurrentPage ? "active" : "")"
                @onclick="@(() => GoToPage(pageNum))">
            @pageNum
        </button>
    }

    <button class="btn btn-page"
            disabled="@(CurrentPage >= TotalPages)"
            @onclick="@(() => GoToPage(CurrentPage + 1))">
        Next
    </button>
</nav>

@code {
    [Parameter]
    public int CurrentPage { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

@page "/catalog"
@namespace sv_2c358796a35e4aa6b17cb47427fc2c1a.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-layout">
    <CatalogSidebar Categories="_categories"
                    OnFilterApplied="HandleFilterApplied"
                    OnFilterCleared="HandleFilterCleared" />

    <main class="catalog-main">
        @if (_error is not null)
        {
            <div class="alert alert-error">
                <p>Something went wrong: @_error</p>
                <button class="btn btn-secondary" @onclick="LoadProducts">Retry</button>
            </div>
        }
        else if (_loading)
        {
            <div class="loading-indicator">
                <p>Loading products...</p>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="empty-state">
                <p>No products found. Try adjusting your filters.</p>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@_sortBy"
                            Page="_currentPage"
                            PageSize="PageSize"
                            TotalCount="_result.TotalCount"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="_currentPage"
                               TotalPages="_totalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </main>
</div>

@code {
    private const int PageSize = 12;

    private List<string> _categories = new();
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    private int _totalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / PageSize);

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialData();
    }

    private async Task LoadInitialData()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            _categories = await categoriesTask;
            _result = await productsTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task LoadProducts()
    {
        try
        {
            _loading = true;
            _error = null;
            StateHasChanged();

            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart functionality
        return Task.CompletedTask;
    }
}

