    color: #999;
    font-size: 0.85rem;
    text-align: center;
    padding: 1rem;
}

.product-info {
    padding: 1rem;
}

.product-name {
    margin: 0 0 0.5rem;
    font-size: 1rem;
}

.product-price {
    font-weight: bold;
    color: #2a7d2e;
    margin: 0 0 0.5rem;
}

.product-rating {
    color: #f5a623;
    margin-bottom: 0.5rem;
}

.badge.out-of-stock {
    display: inline-block;
