+    border-radius: 4px;
+    cursor: pointer;
+}
+
+.btn-page:hover:not(:disabled):not(.active) {
+    background: #e9ecef;
+}
+
+.btn-page.active {
+    background: #0d6efd;
+    color: white;
+    border-color: #0d6efd;
+}
+
+.loading-indicator,
+.empty-state,
+.alert-error {
+    text-align: center;
+    padding: 3rem 1rem;
+}
+
+.alert-error {
+    background: #f8d7da;
+    border: 1px solid #f5c6cb;
+    border-radius: 6px;
+    color: #721c24;
+}
